function neighborsOf([x, y]: Cell): Cell[] {
  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
}

function isAliveNextGeneration(liveNeighborCount: number, wasAlive: boolean): boolean {
  return liveNeighborCount === 3 || (liveNeighborCount === 2 && wasAlive);
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, number>();
  const cellsByKey = new Map<string, Cell>();

  for (const liveCell of liveCells) {
    for (const neighbor of neighborsOf(liveCell)) {
      const key = cellKey(neighbor);
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      cellsByKey.set(key, neighbor);
    }
  }

  const result: Cell[] = [];
  for (const [key, cell] of cellsByKey) {
    const count = neighborCounts.get(key) ?? 0;
    if (isAliveNextGeneration(count, liveKeys.has(key))) {
      result.push(cell);
    }
  }
  return result;
}
